export default async function handler(req, res) {
  if (req.method !== 'GET') return res.status(405).end();
  if (req.query.secret !== 'aryes-migrate-2026') return res.status(401).json({ error: 'unauthorized' });
  if (!SB_URL || !SB_SVC) return res.status(500).json({ error: 'missing env vars' });
  const results = { inserted: 0, errors: [] };
  const BATCH = 50;
  for (let i = 0; i < PRODUCTS.length; i += BATCH) {
    const batch = PRODUCTS.slice(i, i + BATCH);
    const r = await fetch(SB_URL + '/rest/v1/products', {
      method: 'POST',
      headers: { apikey: SB_SVC, Authorization: 'Bearer ' + SB_SVC, 'Content-Type': 'application/json', Prefer: 'return=minimal,resolution=merge-duplicates' },
      body: JSON.stringify(batch),
    });
    if (r.ok) { results.inserted += batch.length; }
    else { results.errors.push({ batch: Math.floor(i/BATCH), status: r.status, err: (await r.text()).substring(0,200) }); break; }
  }
  return res.status(200).json({ ok: true, total: PRODUCTS.length, ...results });
}